INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('fb02da99-f59a-4e90-b9dc-b35d5c8b4507','d6d71be0-f573-41b0-8385-308113f0f047',3,'text','ROOTS phải trở thành tiêu chuẩn tuyển dụng, nguyên tắc đào tạo, kim chỉ nam truyền thông và mỏ neo ra quyết định chiến lược.',NULL,NULL,NULL,NULL,NULL);
