INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('2442b012-5fe2-4cf1-80fe-462c14b4e7a9','05-ung-dung-roadmap','d57e0f96-cf18-4a88-a30f-a32f27c9ab3b',4,'Ứng dụng thực tế','ung-dung-thuc-te',4,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4511fffc-83ad-49b0-9883-36f13b0e3eef','2442b012-5fe2-4cf1-80fe-462c14b4e7a9',10,'text','Một ứng viên có thể rất giỏi chuyên môn, nhưng nếu lệch DNA văn hóa, tổ chức vẫn cần dũng cảm từ chối.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0572bbfd-afe1-4315-bc48-708017ae60ee','2442b012-5fe2-4cf1-80fe-462c14b4e7a9',11,'text','Ví dụ: nếu tổ chức đặt **minh bạch** làm giá trị lõi, thì ứng viên có xu hướng che giấu lỗi, né trách nhiệm hoặc đổ lỗi cho người khác sẽ không phù hợp, dù năng lực chuyên môn tốt.',NULL,NULL,NULL,NULL,NULL);
