INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('b22decca-5fe3-4b55-bbda-35acd1770f1d','05-ung-dung-roadmap','8edfbd2a-b5b7-4fcb-992e-8a6bede42511',4,'Strategy &amp; Resilience','strategy-amp-resilience',17,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('10c769ca-bacc-4e1e-b8c7-4ab4ea0ec6d3','b22decca-5fe3-4b55-bbda-35acd1770f1d',33,'text','Trong quản trị chiến lược, **Tenacity** và **Standardized Statement** trở thành mỏ neo định tâm cho Founder và đội ngũ lãnh đạo.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a8310d76-eed1-4dcf-b4bb-40e5a572d851','b22decca-5fe3-4b55-bbda-35acd1770f1d',34,'text','Khi tổ chức đứng trước quyết định lớn, ROOTS phải được dùng như thước đo tối cao.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('4069b381-2341-4b71-be95-6d05b84a51b7','05-ung-dung-roadmap','8edfbd2a-b5b7-4fcb-992e-8a6bede42511',4,'Cách thực thi','cach-thuc-thi',18,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('96a441e4-cdf7-4ba0-b204-481cf6a37dfe','4069b381-2341-4b71-be95-6d05b84a51b7',35,'text','Trước mỗi quyết định chiến lược, ban lãnh đạo cần đối chiếu với ROOTS thông qua 5 câu hỏi:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('565ce84a-fa0b-4ace-a04b-17725c93d0b5','4069b381-2341-4b71-be95-6d05b84a51b7',36,'text','- Quyết định này có phù hợp với Radicle không?- Quyết định này có vi phạm Operating Code không?- Quyết định này có giúp Outreach mạnh hơn không?- Quyết định này có làm tổ chức bền hơn hay chỉ tăng trưởng ngắn hạn?- Quyết định này có đi ngược lại tuyên ngôn chuẩn hóa của tổ chức không?',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('d65928c0-5e2f-4a01-ab23-d2d5eee4d7e1','05-ung-dung-roadmap','8edfbd2a-b5b7-4fcb-992e-8a6bede42511',4,'Ứng dụng thực tế','ung-dung-thuc-te',19,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c9325126-0cec-4ad3-827b-1d6753ec6d53','d65928c0-5e2f-4a01-ab23-d2d5eee4d7e1',37,'text','Khi mở thêm chi nhánh, đầu tư công nghệ lớn, tuyển nhân sự chủ chốt, xử lý khủng hoảng truyền thông hoặc thay đổi mô hình kinh doanh, Founder không chỉ nhìn vào lợi nhuận trước mắt.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('62d253d0-adfe-4fa5-9849-1a0e9d867c34','d65928c0-5e2f-4a01-ab23-d2d5eee4d7e1',38,'text','Founder phải hỏi:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('58b5707b-29f8-4da9-9306-0792ffc2061b','d65928c0-5e2f-4a01-ab23-d2d5eee4d7e1',39,'text','**“Cơ hội này có làm tổ chức lớn lên mà vẫn giữ được gốc không?”**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d97afe3e-00d8-4405-80e1-43a3b6606391','d65928c0-5e2f-4a01-ab23-d2d5eee4d7e1',40,'text','Nếu một cơ hội kinh doanh đi ngược lại Radicle, tổ chức cần dũng cảm từ chối.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6852cd54-e66a-4fce-b569-b649f3db0631','d65928c0-5e2f-4a01-ab23-d2d5eee4d7e1',41,'text','Nếu một chiến dịch truyền thông tạo tăng trưởng nhưng làm suy giảm niềm tin, tổ chức không nên triển khai.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('80049e62-8dd4-4710-b3b2-c8a604ce736c','d65928c0-5e2f-4a01-ab23-d2d5eee4d7e1',42,'text','Nếu một quyết định giúp tăng doanh thu nhưng phá vỡ Operating Code, quyết định đó cần được xem lại.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('7cbe1088-9896-4509-99d5-d7463d09dffe','05-ung-dung-roadmap','8edfbd2a-b5b7-4fcb-992e-8a6bede42511',4,'Kết quả cần đạt','ket-qua-can-at',20,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2df756b8-4417-4b33-8b76-7bce05ce87db','7cbe1088-9896-4509-99d5-d7463d09dffe',43,'text','- Bộ câu hỏi ra quyết định chiến lược theo ROOTS.- Bộ nguyên tắc vượt khủng hoảng.- Tuyên ngôn văn hóa dùng trong truyền thông nội bộ.- Cơ chế giữ đội ngũ không mất phương hướng khi thị trường biến động.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('a46d8a2b-a3fc-4d2f-a97d-2a65f8673f07','05-ung-dung-roadmap',NULL,2,'ROOTS Application Map','roots-application-map',21,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('898ce7c9-59d8-4ea4-83a5-90674baaac54','a46d8a2b-a3fc-4d2f-a97d-2a65f8673f07',44,'image',NULL,'book/05-ung-dung-roadmap/7c86e4f8-5e02-4ea8-aad6-c3345ef8eccc-img02.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('0383973e-0445-493b-9313-5aabd3523e90','05-ung-dung-roadmap',NULL,2,'Công thức ứng dụng ROOTS','cong-thuc-ung-dung-roots',22,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('129c08cf-17cf-40bd-8fb8-711c87b801be','0383973e-0445-493b-9313-5aabd3523e90',45,'text','ROOTS cần được triển khai theo công thức:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('be81c900-e1fa-4f7e-9adc-ea253aedd86e','0383973e-0445-493b-9313-5aabd3523e90',46,'image',NULL,'book/05-ung-dung-roadmap/a2f91367-22fe-4075-afbb-0e005fa03ca2-img03.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('8a12e779-776a-4b9a-93c1-cc3713460891','0383973e-0445-493b-9313-5aabd3523e90',47,'text','Nói ngắn gọn:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9c1aba9e-c2a3-47de-98fd-ae4cc2565494','0383973e-0445-493b-9313-5aabd3523e90',48,'text','**ROOTS không chỉ để viết ra. ROOTS phải được tuyển vào, dạy lại, truyền thông ra ngoài và dùng để ra quyết định.**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('b0f21a1b-fbcd-4b99-9106-55ca4a4d722d','05-ung-dung-roadmap',NULL,2,'Kết luận','ket-luan',23,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ad2198bb-17e7-4be4-a0d8-81baefe7498e','b0f21a1b-fbcd-4b99-9106-55ca4a4d722d',49,'text','Xác định ROOTS là quá trình tìm ra **mã gen gốc** của tổ chức.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6a79551b-150f-489a-b3f4-a2abacbca8a0','b0f21a1b-fbcd-4b99-9106-55ca4a4d722d',50,'text','Ứng dụng ROOTS là quá trình **nhân bản mã gen đó** vào từng tế bào vận hành.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('37403e9a-9a64-44bf-9c0e-4bea8a4ba20f','b0f21a1b-fbcd-4b99-9106-55ca4a4d722d',51,'text','Khi ROOTS đủ chắc, tổ chức không chỉ tăng trưởng nhanh hơn mà còn tăng trưởng đúng hướng hơn. Đội ngũ biết mình đang phục vụ điều gì. Khách hàng cảm nhận được sự nhất quán. Founder có mỏ neo để ra quyết định. Và toàn bộ các tầng phía sau của R.O.A.D.M.A.P từ **ONE LIGHT**, **AWAKEN**, **DEEPEN**, **MATURE**, **ALIGN** cho đến **PROSPER** mới có nền móng vững chắc để sinh trưởng tự nhiên.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d8bd3e59-0192-40c9-b265-b0972dbee705','b0f21a1b-fbcd-4b99-9106-55ca4a4d722d',52,'text','- **ROOTS là nơi tổ chức bám rễ trước khi vươn cành.**- **Không có gốc rễ, tăng trưởng chỉ là mở rộng bề mặt.**- **Có ROOTS, tăng trưởng trở thành sự trưởng thành có định hướng.**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('1e928489-f9e7-4d00-874c-e91f1f12a724','05-ung-dung-roadmap',NULL,1,'5.2 ONE LIGHT','52-one-light',24,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('714db243-1ba9-4e51-942d-9f297592ae29','05-ung-dung-roadmap','1e928489-f9e7-4d00-874c-e91f1f12a724',2,'Các giai đoạn thực thi ONE LIGHT','cac-giai-oan-thuc-thi-one-light',25,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a7fc6677-55c9-47ca-8216-f65ece813427','714db243-1ba9-4e51-942d-9f297592ae29',53,'text','ONE LIGHT không nên dừng ở câu khẩu hiệu. Nó phải được triển khai thành chuẩn mực tổ chức, quy trình, nội dung và cơ chế ra quyết định để tạo ra sự nhất quán thật.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('dea51875-1b09-499e-a278-67a7a7abb39d','714db243-1ba9-4e51-942d-9f297592ae29',54,'text','- Xác lập ánh sáng gốc: chốt tổ chức là ai, theo đuổi điều gì, và đâu là chuẩn mực không được vượt qua; giai đoạn này thuộc Strategy OS và People OS.- Chuẩn hóa cách sống ánh sáng: biến tinh thần One và Light thành cách phối hợp, cách giao tiếp, cách xử lý lỗi và cách làm việc mỗi ngày; phần này phải đi vào Role Card, onboarding và SOP.- Phát sáng ra thị trường: chuyển bản sắc thành content, trust assets, website, Google Map, case và review để khách hàng nhìn thấy sự nhất quán của thương hiệu.- Dẫn đường cho hành trình khách hàng: thiết kế các tầng từ Traffic đến Trust, Relationship, Authority Check, Search Layer và Conversion để ánh sáng đi được từ nhận biết đến hành động.- Giữ sáng khi mở rộng: dùng Data OS, Finance OS và review chiến lược định kỳ để tổ chức không mất gốc khi tăng trưởng nhanh.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('8c594e95-acf0-4997-b36a-9dc9c58537f5','05-ung-dung-roadmap','1e928489-f9e7-4d00-874c-e91f1f12a724',2,'ONE LIGHT application map','one-light-application-map',26,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6de7f05a-d398-4568-a79a-48b408125506','8c594e95-acf0-4997-b36a-9dc9c58537f5',55,'image',NULL,'book/05-ung-dung-roadmap/07eaaac5-7cd7-4fff-bba8-c9e0b8f1f906-img04.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('876540d2-8482-47c4-880e-da4ce54bbbc1','8c594e95-acf0-4997-b36a-9dc9c58537f5',56,'text','ONE LIGHT application map này giúp tổ chức đi từ “cùng một niềm tin” đến “cùng một cách làm” và cuối cùng là “cùng một kết quả”. Mô hình Dental OS cho thấy nếu không có cấu trúc này, chiến lược sẽ không xuống được vận hành, còn vận hành sẽ không tạo ra tăng trưởng bền.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('9df1dc81-bd2f-4516-a2ab-b6b5fd92c097','05-ung-dung-roadmap','1e928489-f9e7-4d00-874c-e91f1f12a724',2,'Công thức ứng dụng','cong-thuc-ung-dung',27,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('03d1090e-bdf2-4d74-9352-4e3de54706e0','9df1dc81-bd2f-4516-a2ab-b6b5fd92c097',57,'text','Công thức ứng dụng ONE LIGHT trong tổ chức có thể viết ngắn gọn như sau:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9b0d34a4-7ade-4e64-ae62-aa280e7f457f','9df1dc81-bd2f-4516-a2ab-b6b5fd92c097',58,'text','**ONE LIGHT = One team, One standard, One message, One decision system.**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9eb9119a-9892-4180-99cb-5adec5e95056','9df1dc81-bd2f-4516-a2ab-b6b5fd92c097',59,'text','Diễn giải theo vận hành:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('883cff64-8afc-45ff-8186-01f8e6c39623','9df1dc81-bd2f-4516-a2ab-b6b5fd92c097',60,'text','- One team: tuyển và giữ người cùng tinh thần, cùng hệ giá trị, cùng mục tiêu.- One standard: dùng một chuẩn chung cho onboarding, công việc, đánh giá và phối hợp.- One message: mọi nội dung, review, case, website và Google Map phải kể cùng một câu chuyện thương hiệu.- One decision system: quyết định lớn phải đi qua Strategy, Finance và Data thay vì cảm tính cá nhân.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9781b353-1bcf-41e8-970f-11c5950278c8','9df1dc81-bd2f-4516-a2ab-b6b5fd92c097',61,'text','Nói cách khác, ONE LIGHT là cách biến sự rõ ràng thành một hệ thống có thể lặp lại. Khi tổ chức đã có chuẩn chung, người mới vào dễ hòa nhập hơn, quản lý dễ điều phối hơn và khách hàng dễ nhận ra bản sắc hơn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e86afb9e-a331-46ae-8626-c801ad6dca5f','9df1dc81-bd2f-4516-a2ab-b6b5fd92c097',62,'image',NULL,'book/05-ung-dung-roadmap/840b9911-0c6c-45c5-af75-a1f0b1e66234-img05.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('5912ffd4-cc2e-43a8-91e1-e8bd3de68b5c','05-ung-dung-roadmap','1e928489-f9e7-4d00-874c-e91f1f12a724',2,'Đúc kết','uc-ket',28,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0c1f96cd-d22f-45d5-b3a3-6a59b19687dd','5912ffd4-cc2e-43a8-91e1-e8bd3de68b5c',63,'text','ONE LIGHT là bản đồ để tổ chức vừa **mở** ra thị trường, vừa giữ được sự đồng bộ bên trong. Nếu Root là gốc, thì ONE LIGHT là phần ánh sáng giúp cái gốc ấy được nhìn thấy, được hiểu đúng và được vận hành nhất quán.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a5f2793e-c6cc-4abc-bd60-df31efed5f38','5912ffd4-cc2e-43a8-91e1-e8bd3de68b5c',64,'text','Công thức mạnh nhất của ONE LIGHT là: **rõ người, rõ chuẩn, rõ thông điệp, rõ hành trình, rõ quyết định**. Khi năm lớp này khớp nhau, tổ chức không chỉ tăng trưởng nhanh hơn mà còn tăng trưởng có bản sắc và có kiểm soát.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('b3c5558c-c6b6-4606-a5b8-9de9384ab139','05-ung-dung-roadmap',NULL,1,'5.3 AWAKEN','53-awaken',29,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('4d4d38d3-bc40-4d5a-a9ca-77d07208f1e8','05-ung-dung-roadmap','b3c5558c-c6b6-4606-a5b8-9de9384ab139',2,'A - Audit','a-audit',30,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9fddb078-9818-4de1-9135-42f54c0e453f','4d4d38d3-bc40-4d5a-a9ca-77d07208f1e8',65,'text','**Mục tiêu của bước này**
Audit dùng để kiểm tra thực trạng nội bộ của hệ thống, phát hiện điểm mạnh, điểm yếu và lỗi vận hành đang ảnh hưởng đến kết quả chung. Bước này giúp phòng khám nhìn đúng tình hình trước khi đưa ra bất kỳ quyết định cải tiến nào.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('df2a3b4c-76a4-482b-a73a-6f6d97682ce8','4d4d38d3-bc40-4d5a-a9ca-77d07208f1e8',66,'text','**Dấu hiệu cần thực hiện**
Thực hiện khi KPI tụt, khi có nhiều lỗi lặp lại, khi doanh thu hoặc trải nghiệm khách không ổn định, hoặc khi hệ thống sắp bước vào một giai đoạn tăng trưởng mới. Đây cũng là bước cần làm định kỳ để tránh đội ngũ làm việc theo cảm tính.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('de0105db-2ff9-4c30-bb0d-52e95f377b69','4d4d38d3-bc40-4d5a-a9ca-77d07208f1e8',67,'text','**Cách thực hiện**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('24d08dad-2a5d-472b-b71c-85bf012c4739','4d4d38d3-bc40-4d5a-a9ca-77d07208f1e8',68,'text','- Thu thập dữ liệu từ các module liên quan như Strategy, Marketing, Sales, Clinic, Patient, Finance, People và Data.- Kiểm tra thực tế quy trình, checklist, dashboard, báo cáo và kết quả đầu ra.- Ghi nhận lỗi, mức độ ảnh hưởng, nguyên nhân sơ bộ và mức ưu tiên xử lý.- Chốt danh sách việc cần sửa ngay và việc cần theo dõi tiếp.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('363ed8ec-d2a7-4265-bbd5-ca0e7a8c2772','4d4d38d3-bc40-4d5a-a9ca-77d07208f1e8',69,'text','**Đầu ra bắt buộc**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e43f004e-4082-4a08-907c-673eabebbc80','4d4d38d3-bc40-4d5a-a9ca-77d07208f1e8',70,'text','- Audit report.- Danh sách lỗi theo mức độ ưu tiên.- Danh sách việc cần xử lý ngay.- Danh sách điểm cần theo dõi tiếp theo.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5f694cbb-4a9f-49a5-b852-7b5a2d0a3200','4d4d38d3-bc40-4d5a-a9ca-77d07208f1e8',71,'text','**Người phụ trách**
Chính: Founder, Clinic Manager hoặc Data Lead tùy giai đoạn.
Phối hợp: các trưởng bộ phận liên quan.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f38fa4b6-3917-481b-909b-c95052e47b45','4d4d38d3-bc40-4d5a-a9ca-77d07208f1e8',72,'text','**KPI / tín hiệu theo dõi**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d7353f05-232c-4644-90fd-1e542a239ce3','4d4d38d3-bc40-4d5a-a9ca-77d07208f1e8',73,'text','- Số lỗi phát hiện.- Tỷ lệ lỗi có owner.- Tỷ lệ lỗi được xử lý đúng hạn.- Số lỗi tái diễn sau khi sửa.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('0df4f467-f642-482b-8707-698b80ed77b5','05-ung-dung-roadmap','b3c5558c-c6b6-4606-a5b8-9de9384ab139',2,'W - Watch','w-watch',31,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0bc26f01-acc2-492e-a4c7-c29885c3f268','0df4f467-f642-482b-8707-698b80ed77b5',74,'text','**Mục tiêu của bước này**
Watch dùng để quan sát thị trường, đối thủ, khách hàng và xu hướng bên ngoài để nhận ra cơ hội và rủi ro sớm. Bước này giúp hệ thống không chỉ nhìn vào nội bộ mà còn hiểu môi trường đang thay đổi thế nào.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('3a5b1e79-3364-46b2-9186-9ed4c854f17e','0df4f467-f642-482b-8707-698b80ed77b5',75,'text','**Dấu hiệu cần thực hiện**
Thực hiện khi thị trường có biến động, đối thủ ra thông điệp mới, hành vi khách hàng thay đổi, hoặc khi team cần xác định hướng nội dung và chiến lược tiếp cận mới. Đây là bước đặc biệt hữu ích trước khi lập kế hoạch marketing hoặc tăng trưởng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('cd426a8d-fa70-4115-b95b-0864bc47da19','0df4f467-f642-482b-8707-698b80ed77b5',76,'text','**Cách thực hiện**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('18aa9d2d-b826-41c2-9996-6805a2635eb1','0df4f467-f642-482b-8707-698b80ed77b5',77,'text','- Theo dõi đối thủ, kênh truyền thông, nội dung, ưu đãi và thông điệp đang được thị trường phản hồi tốt.- Ghi lại câu hỏi khách hàng hay hỏi, nỗi sợ phổ biến, nhu cầu mới và tín hiệu xu hướng.- Tổng hợp thành danh sách insight ngắn, dễ dùng cho chiến lược và content.- Chuyển insight thành các đề xuất hành động.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c92471f5-b115-453c-ae17-50ff60c1e23d','0df4f467-f642-482b-8707-698b80ed77b5',78,'text','**Đầu ra bắt buộc**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b0e8df89-0981-41c5-80b2-95a459a1ffb9','0df4f467-f642-482b-8707-698b80ed77b5',79,'text','- Market watch note.- Competitor map.- Trend list.- Insight list cho content hoặc chiến lược.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('814b9449-f06e-455a-9edc-6147109a2cbd','0df4f467-f642-482b-8707-698b80ed77b5',80,'text','**Người phụ trách**
Chính: Marketing Lead hoặc Strategy Lead.
Phối hợp: Sales, Data, Founder và các đầu mối chuyên môn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('3ab5a64f-5c62-4aef-b9e0-00906a398ae0','0df4f467-f642-482b-8707-698b80ed77b5',81,'text','**KPI / tín hiệu theo dõi**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0906a340-f45f-463e-9a28-29cb0a598beb','0df4f467-f642-482b-8707-698b80ed77b5',82,'text','- Số insight hữu ích mỗi tháng.- Số thay đổi chiến lược tạo ra từ quan sát.- Tỷ lệ insight được đưa vào plan thực tế.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('3b5cfcf0-af69-4737-ae3d-455f64b85187','05-ung-dung-roadmap','b3c5558c-c6b6-4606-a5b8-9de9384ab139',2,'M - Map','m-map',32,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('004e443c-da5a-4838-8cb8-a1f96b020224','3b5cfcf0-af69-4737-ae3d-455f64b85187',83,'text','**Mục tiêu của bước này**
Map dùng để vẽ bản đồ hiện trạng, tức là ghép dữ liệu và quan sát thành một sơ đồ rõ ràng về hệ thống đang vận hành ra sao. Bước này giúp xác định khoảng cách giữa trạng thái hiện tại và trạng thái mục tiêu.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5730b171-dd0d-4e40-927d-ea76a3200d64','3b5cfcf0-af69-4737-ae3d-455f64b85187',84,'text','**Dấu hiệu cần thực hiện**
Thực hiện khi team cần hiểu điểm nghẽn, khi các bộ phận đang nhìn vấn đề khác nhau, hoặc khi cần lập kế hoạch cải tiến theo luồng vận hành. Đây cũng là bước quan trọng trước khi tối ưu Customer Journey hoặc Dental OS module.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('63e8c0bf-0e0c-4b5f-9b11-ce23f3059010','3b5cfcf0-af69-4737-ae3d-455f64b85187',85,'text','**Cách thực hiện**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('440f92f7-a9ac-4e59-bde2-42f2cea99077','3b5cfcf0-af69-4737-ae3d-455f64b85187',86,'text','- Vẽ luồng từ đầu vào đến đầu ra, ví dụ: traffic → trust → relationship → conversion → patient experience → referral.- Gắn từng điểm rơi với kênh, quy trình, owner và dữ liệu hiện có.- Đánh dấu nơi bị rơi khách, nơi tắc nghẽn, nơi thiếu dữ liệu, nơi thiếu người phụ trách.- Chuyển sơ đồ thành danh sách ưu tiên cải tiến.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('11fba416-4bf3-4ba9-95eb-e6c7906358c2','3b5cfcf0-af69-4737-ae3d-455f64b85187',87,'text','**Đầu ra bắt buộc**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4eebb995-732c-4c73-a6f7-8c0970f8e5ad','3b5cfcf0-af69-4737-ae3d-455f64b85187',88,'text','- Journey map.- Gap map.- Bottleneck map.- Ownership map.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('173e0acc-1369-4309-b6a5-78b5d82f06eb','3b5cfcf0-af69-4737-ae3d-455f64b85187',89,'text','**Người phụ trách**
Chính: Data Lead, Strategy Lead hoặc Manager.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7a2fd38d-92f4-42e1-a03e-25591dd40b37','3b5cfcf0-af69-4737-ae3d-455f64b85187',90,'text','Phối hợp: Marketing, Sales, Clinic, Patient Care và Finance.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d65fecac-bcd3-44cf-b3eb-5c48d5ed400d','3b5cfcf0-af69-4737-ae3d-455f64b85187',91,'text','**KPI / tín hiệu theo dõi**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('70004b4f-d357-4138-a9aa-a499e00d908d','3b5cfcf0-af69-4737-ae3d-455f64b85187',92,'text','- Số điểm nghẽn được xác định rõ.- Tỷ lệ tầng có dữ liệu đầy đủ.- Số vấn đề được gán owner sau khi map.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('b8e976a2-56cd-4464-b9bd-dd3bbb6083d6','05-ung-dung-roadmap','b3c5558c-c6b6-4606-a5b8-9de9384ab139',2,'K - Know','k-know',33,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('729a67d3-1234-46bb-9a0d-1eddd3a631f6','b8e976a2-56cd-4464-b9bd-dd3bbb6083d6',93,'text','**Mục tiêu của bước này**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d583f96e-46e1-46d2-a3a6-d775591e924d','b8e976a2-56cd-4464-b9bd-dd3bbb6083d6',94,'text','Know dùng để chốt lại sự thật hệ thống: điều gì đang diễn ra thật sự, thay vì điều gì mọi người nghĩ đang diễn ra. Bước này giúp tạo một “statement of reality” để cả đội cùng nhìn về một mặt trận dữ liệu thống nhất.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('af8c244e-3440-463b-bad0-810592080721','b8e976a2-56cd-4464-b9bd-dd3bbb6083d6',95,'text','**Dấu hiệu cần thực hiện**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c9d3da8c-5243-4d94-a14f-9674503862aa','b8e976a2-56cd-4464-b9bd-dd3bbb6083d6',96,'text','Thực hiện khi có sự khác biệt giữa cảm nhận và số liệu, khi các bộ phận tranh luận về nguyên nhân, hoặc khi cần xác định ưu tiên xử lý đúng. Bước này thường đi sau Audit và Map.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d7d3d057-eee9-4ab7-b00e-6560c6ea00d4','b8e976a2-56cd-4464-b9bd-dd3bbb6083d6',97,'text','**Cách thực hiện**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d21693d5-8c13-47f0-aa90-fadb15ffde88','b8e976a2-56cd-4464-b9bd-dd3bbb6083d6',98,'text','- Đọc lại dữ liệu từ audit và map.- Chốt các sự thật quan trọng nhất: cái gì đang tăng, cái gì đang giảm, cái gì đang gây rò rỉ, cái gì đang tạo kết quả.- Viết thành các câu kết luận ngắn, rõ và có số liệu đi kèm.- Xác nhận với các bên liên quan để thống nhất nhận thức.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('eb2bead9-9a2f-498e-9d03-9689cee520e0','b8e976a2-56cd-4464-b9bd-dd3bbb6083d6',99,'text','**Đầu ra bắt buộc**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('35252e45-c16c-4de9-8d7e-ae44dd3ea551','b8e976a2-56cd-4464-b9bd-dd3bbb6083d6',100,'text','- Reality statement.- Priority list.- Decision list.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b95f8c2b-ab85-40a0-80f1-10d6b60f2cb3','b8e976a2-56cd-4464-b9bd-dd3bbb6083d6',101,'text','**Người phụ trách**
Chính: Founder hoặc Data Lead.
Phối hợp: các trưởng bộ phận liên quan.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ab07dea2-beca-4d8c-bb41-3c7ff70a1399','b8e976a2-56cd-4464-b9bd-dd3bbb6083d6',102,'text','**KPI / tín hiệu theo dõi**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2b5dd8d6-b7e7-4419-b7ea-546abab252fa','b8e976a2-56cd-4464-b9bd-dd3bbb6083d6',103,'text','- Tỷ lệ quyết định dựa trên dữ liệu.- Số quyết định được thống nhất sau review.- Tỷ lệ tranh luận giảm vì đã có số liệu chung.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('b219c74c-afae-41b4-bac0-b4d41ae08b97','05-ung-dung-roadmap','b3c5558c-c6b6-4606-a5b8-9de9384ab139',2,'E - Examine','e-examine',34,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('bff98fb8-a8fc-48b3-88d7-18f98a286e54','b219c74c-afae-41b4-bac0-b4d41ae08b97',104,'text','**Mục tiêu của bước này**
Examine dùng để đào sâu nguyên nhân gốc, không dừng ở triệu chứng. Đây là bước biến vấn đề bề mặt thành hiểu biết hệ thống về cơ chế tạo ra vấn đề đó.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('8743cfb0-f820-470f-a6a1-d171e44203c5','b219c74c-afae-41b4-bac0-b4d41ae08b97',105,'text','**Dấu hiệu cần thực hiện**
Thực hiện khi một lỗi lặp lại nhiều lần, khi KPI không cải thiện dù đã sửa bề mặt, hoặc khi cần thiết kế biện pháp can thiệp thật sự hiệu quả.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4f52307d-1d66-4981-809a-e6f06b63da26','b219c74c-afae-41b4-bac0-b4d41ae08b97',106,'text','**Cách thực hiện**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('26203d0b-d381-42ed-a8a5-7c224f416cdf','b219c74c-afae-41b4-bac0-b4d41ae08b97',107,'text','- Chọn một vấn đề cụ thể để phân tích.- Hỏi tại sao nhiều vòng, kiểm tra quy trình, con người, công cụ, dữ liệu và bàn giao.- Xác định nguyên nhân gốc, nguyên nhân phụ và điểm can thiệp tốt nhất.- Chuyển kết quả thành kế hoạch sửa lỗi hoặc cải tiến quy trình.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('3ce0e23b-a9cb-47a6-ad26-fc4e8d33bc44','b219c74c-afae-41b4-bac0-b4d41ae08b97',108,'text','**Đầu ra bắt buộc**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6dbdec38-f8e2-463d-9a26-a114d072ba0d','b219c74c-afae-41b4-bac0-b4d41ae08b97',109,'text','- Root cause map.- Corrective action plan.- Danh sách thay đổi quy trình hoặc huấn luyện cần làm.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('22f6b64c-4e50-4e88-9a5e-024fc4f9acc4','b219c74c-afae-41b4-bac0-b4d41ae08b97',110,'text','**Người phụ trách**
Chính: Manager, Data Lead hoặc owner của vấn đề.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9ad2da9b-6fd9-411d-9c07-a445fd04c6df','b219c74c-afae-41b4-bac0-b4d41ae08b97',111,'text','Phối hợp: người trực tiếp vận hành và các bên liên quan.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('30678b0a-240b-4e91-9b49-40243e38537c','b219c74c-afae-41b4-bac0-b4d41ae08b97',112,'text','**KPI / tín hiệu theo dõi**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('57420395-7eaa-457e-87b5-f88871e5b716','b219c74c-afae-41b4-bac0-b4d41ae08b97',113,'text','- Số nguyên nhân gốc được xác định.- Số lỗi tái diễn giảm xuống.- Tỷ lệ action khắc phục được hoàn tất.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('49f0685d-bca6-4f89-a9e2-25d82a57351f','05-ung-dung-roadmap','b3c5558c-c6b6-4606-a5b8-9de9384ab139',2,'N - Notice','n-notice',35,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c792afce-b16b-4119-a594-44400eec86f1','49f0685d-bca6-4f89-a9e2-25d82a57351f',114,'text','**Mục tiêu của bước này**
Notice dùng để nhận ra tín hiệu sớm trước khi vấn đề trở thành sự cố lớn. Đây là tầng cảnh báo sớm giúp hệ thống phản ứng kịp thời thay vì chờ đến khi hậu quả đã rõ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('57c90032-ec5d-4a4a-8992-ea4a712c1dc5','49f0685d-bca6-4f89-a9e2-25d82a57351f',115,'text','**Dấu hiệu cần thực hiện**
Thực hiện khi xuất hiện những dấu hiệu nhỏ nhưng lặp lại: chậm phản hồi, giảm tương tác, khiếu nại tăng nhẹ, lệch dữ liệu nhỏ, hay một số chỉ số vận hành trượt dần.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d2b50182-b231-4a71-bddb-d19fd6b88f40','49f0685d-bca6-4f89-a9e2-25d82a57351f',116,'text','**Cách thực hiện**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c8eeeb32-93f5-4e79-a8b4-4af8bab935b5','49f0685d-bca6-4f89-a9e2-25d82a57351f',117,'text','- Thiết lập rule cảnh báo cho các chỉ số quan trọng.- Theo dõi tín hiệu bất thường theo tuần hoặc theo ngày tùy module.- Ghi nhận cảnh báo vào issue tracker và giao người xử lý.- Kiểm tra lại sau khi xử lý để biết tín hiệu đó có biến mất không.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('87aec846-f974-4e48-a8e6-7f33d6e6c87e','49f0685d-bca6-4f89-a9e2-25d82a57351f',118,'text','**Đầu ra bắt buộc**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0dd05a1d-1563-4ba3-9999-238fcbfe6940','49f0685d-bca6-4f89-a9e2-25d82a57351f',119,'text','- Alert rule sheet.- Issue tracker.- Danh sách cảnh báo đã xử lý.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9ea6a225-3951-4341-9e68-7c66214079b9','49f0685d-bca6-4f89-a9e2-25d82a57351f',120,'text','**Người phụ trách**
Chính: Data Lead hoặc Operations Lead.
Phối hợp: owner của từng module và người trực tiếp vận hành.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1dcdcfb6-4d99-4dd8-96a5-1b84dc7127f4','49f0685d-bca6-4f89-a9e2-25d82a57351f',121,'text','**KPI / tín hiệu theo dõi**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2e808341-2d4b-4339-8b75-b2ac71ce364e','49f0685d-bca6-4f89-a9e2-25d82a57351f',122,'text','- Số cảnh báo phát hiện sớm.- Thời gian phản ứng với cảnh báo.- Tỷ lệ vấn đề được chặn trước khi thành sự cố',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('aeb6325e-ff2e-49d3-b688-8c7fa4fd7339','05-ung-dung-roadmap',NULL,1,'5.4 DEEPEN','54-deepen',36,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('7fa8d241-1589-4273-a843-9ca510b51427','05-ung-dung-roadmap','aeb6325e-ff2e-49d3-b688-8c7fa4fd7339',2,'D - Define','d-define',37,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('79fde83c-547c-4d7e-91c0-db8bb1ed43d4','7fa8d241-1589-4273-a843-9ca510b51427',123,'text','**Định Vị Chuẩn Hóa**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ee7fcdb5-5cda-4ee4-96ea-d8702e7b0616','7fa8d241-1589-4273-a843-9ca510b51427',124,'text','**Mục tiêu của bước này:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('31bb30af-9343-4356-933c-8c9157f0fd1a','7fa8d241-1589-4273-a843-9ca510b51427',125,'text','Define là bước xác định rõ điều gì cần được đào sâu. Tổ chức phải nói rõ mình đang cần chuẩn hóa năng lực nào, quy trình nào, vấn đề nào hoặc hành vi nào. Nếu không định nghĩa rõ, mọi nỗ lực cải tiến sẽ rất dễ lan man và thiếu trọng tâm. Define giúp hệ thống trả lời câu hỏi: ta đang cần làm sâu cái gì, và vì sao nó quan trọng đến mức phải chuẩn hóa.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ed5804a3-a5b0-4985-afff-c60ca82357b6','7fa8d241-1589-4273-a843-9ca510b51427',126,'text','**Dấu hiệu cần thực hiện:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7c968219-7605-4ae6-a1bc-6d9020691e4d','7fa8d241-1589-4273-a843-9ca510b51427',127,'text','Thực hiện khi câu hỏi còn mơ hồ, khi nhiều người đang hiểu khác nhau về cùng một vấn đề, hoặc khi một luồng việc thực tế đang vận hành lỏng lẻo, trồi sụt kết quả nhưng chưa ai gọi đúng tên tiêu chuẩn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('8c06d797-542d-4f02-a51e-7046faf628e6','7fa8d241-1589-4273-a843-9ca510b51427',128,'text','**Cách thực hiện:**- Viết một câu mô tả năng lực hoặc quy trình cần chuẩn hóa thật ngắn và cụ thể.- Xác định rõ phạm vi (Scope): thuộc Vòng tròn (Circle) nào, giai đoạn nào trong hành trình, nhóm nhân sự nào sở hữu.- Chốt các tiêu chí cốt lõi để biết đối tượng này đã được định nghĩa đúng trọng tâm.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('dd0b39aa-a1d4-49c0-8e1e-18fd902160d2','7fa8d241-1589-4273-a843-9ca510b51427',129,'text','**Đầu ra bắt buộc:**- Standardization Target Statement (Tuyên bố mục tiêu chuẩn hóa chung).- Scope statement (Văn bản xác định phạm vi quy trình).- Target criteria checklist (Checklist tiêu chí công nhận).',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d491d25f-0a71-47a6-a29c-44d5a95ccd47','7fa8d241-1589-4273-a843-9ca510b51427',130,'text','**Người phụ trách:** Circle Lead của bộ phận đó phối hợp với Trainer (Chuyên viên đào tạo SOP) và owner của vấn đề/quy trình.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5e85d3cd-37af-466d-ab2c-f4b1fc5c83b5','7fa8d241-1589-4273-a843-9ca510b51427',131,'text','**KPI / tín hiệu theo dõi:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('8c806c2d-7edc-4cc3-9f1b-aa9c1393efbf','7fa8d241-1589-4273-a843-9ca510b51427',132,'text','- Mức độ rõ ràng và thống nhất của mục tiêu chuẩn hóa giữa các bên liên quan (đạt 100%).- Số lần hệ thống phải chỉnh sửa lại câu định nghĩa trong chu kỳ',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('51eeca24-45b6-433b-bc5e-52600db02dc3','05-ung-dung-roadmap','aeb6325e-ff2e-49d3-b688-8c7fa4fd7339',2,'E - Enhance','e-enhance',38,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('195ed4bf-965d-4ebd-8159-480a2841a427','51eeca24-45b6-433b-bc5e-52600db02dc3',133,'text','**Nâng Chất Thực Thi**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2cbd74c5-8764-4662-baa8-8443d0ed3ade','51eeca24-45b6-433b-bc5e-52600db02dc3',134,'text','**Mục tiêu của bước này:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5df28921-ed18-4890-b90c-ee1e1099ce00','51eeca24-45b6-433b-bc5e-52600db02dc3',135,'text','Enhance là nâng chất lượng của năng lực hoặc cách làm lên mức tốt hơn. Không phải cái gì cũng cần tạo mới hoàn toàn; nhiều khi vấn đề là cái đang có chưa đủ mạnh, chưa đủ tốt, chưa đủ ổn định để trở thành nền tảng dài hạn. Enhance là bước làm cho cái đúng trở nên tốt hơn, sắc hơn và mạnh hơn trước khi đưa nó vào hệ thống hóa.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('bdb6f691-7fa7-4cdc-bea1-9d94d31822ac','51eeca24-45b6-433b-bc5e-52600db02dc3',136,'text','**Dấu hiệu cần thực hiện:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2a79f1a4-d953-4c33-83bb-f663d7690a7f','51eeca24-45b6-433b-bc5e-52600db02dc3',137,'text','Khi quy trình hiện tại bộc lộ hiệu suất kém, hoặc khi đã tìm thấy các cách làm tốt nhất (Best Practices) từ các nhân sự xuất sắc nhưng chúng chưa được mài sắc để có thể áp dụng cho số đông.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('65ae9423-7f88-451a-9981-b950fc5ad030','51eeca24-45b6-433b-bc5e-52600db02dc3',138,'text','**Cách thực hiện:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('fd1c4542-6d21-4073-8444-e2db95f1cb33','51eeca24-45b6-433b-bc5e-52600db02dc3',139,'text','- Khảo sát và ghi nhận trực tiếp các thao tác, hành vi tạo ra hiệu suất cao nhất tại các điểm chạm lâm sàng hoặc dịch vụ. - Loại bỏ các bước thừa thãi gây tắc nghẽn, tập trung nâng cấp các bước tạo ra giá trị hoặc trải nghiệm cao. - Chạy thử nghiệm điều chỉnh ở quy mô nhỏ để kiểm chứng hiệu quả nâng chất trước khi đóng gói.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5cce5c4e-7b53-4837-87a7-0a5b9184482b','51eeca24-45b6-433b-bc5e-52600db02dc3',140,'text','**Đầu ra bắt buộc:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('bbca024b-56bf-4fb4-b275-c2b15568a876','51eeca24-45b6-433b-bc5e-52600db02dc3',141,'text','- Best-Practice Logbook (Nhật ký ghi nhận cách làm tối ưu thực tế).  - Optimized Model Sheet (Bản mô tả mô hình thực thi sau khi đã mài sắc.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ebeff922-29bc-4ad4-8c86-0a616453ff35','51eeca24-45b6-433b-bc5e-52600db02dc3',142,'text','**Người phụ trách:** Chuyên gia chuyên môn của Circle (Bác sĩ trưởng, Trưởng bộ phận CSKH, Consultant Leader) phối hợp với người vận hành trực tiếp.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6334a554-2534-4545-bfdb-42b8286f98b1','51eeca24-45b6-433b-bc5e-52600db02dc3',143,'text','**KPI / tín hiệu theo dõi:**- Tỷ lệ cải thiện hiệu suất của quy trình/năng lực sau khi nâng chất (Đo lường trước khi đóng gói).  - Số lượng điểm cải tiến nâng chất được hội đồng chuyên môn ghi nhận.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('eecfe7d7-04d1-4a9a-84dc-1a822a1fc7e8','05-ung-dung-roadmap','aeb6325e-ff2e-49d3-b688-8c7fa4fd7339',2,'E - Elaborate','e-elaborate',39,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('8eb3b0e6-4328-4bb9-b9d5-32f29c848e6b','eecfe7d7-04d1-4a9a-84dc-1a822a1fc7e8',144,'text','**Chi Tiết Hóa Tiêu Chuẩn**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('293f0c21-f744-455d-80c1-979c968216fc','eecfe7d7-04d1-4a9a-84dc-1a822a1fc7e8',145,'text','**Mục tiêu của bước này:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('88aae31e-5719-429c-9df9-d8e3ceb436bf','eecfe7d7-04d1-4a9a-84dc-1a822a1fc7e8',146,'text','Ở bước này, tổ chức bóc tách từng bước, từng điều kiện, từng tiêu chuẩn, từng ngoại lệ và từng tình huống có thể xảy ra. Một tiêu chuẩn nếu chưa được làm rõ thì vẫn chỉ là khái niệm. Elaborate giúp biến điều mơ hồ thành điều có thể dạy, có thể theo dõi và có thể kiểm tra.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('58064fb9-652d-4bc9-893b-6716fc6e35d9','eecfe7d7-04d1-4a9a-84dc-1a822a1fc7e8',147,'text','**Dấu hiệu cần thực hiện:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b0ffa0b1-86cf-4c60-abfc-266792a11cd8','eecfe7d7-04d1-4a9a-84dc-1a822a1fc7e8',148,'text','Khi các tiêu chuẩn mới chỉ dừng lại ở mặt từ ngữ trừu tượng, cảm tính (ví dụ: "tư vấn nhiệt tình", "vô trùng kỹ lưỡng") khiến nhân sự cấp dưới mơ hồ, lúng túng khi thực hiện thực tế).',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2b2ff712-b541-4a6a-b843-838940e61c28','eecfe7d7-04d1-4a9a-84dc-1a822a1fc7e8',149,'text','**Cách thực hiện:**Chia nhỏ quy trình tổng thể thành một ma trận các bước chi tiết theo tiến trình lâm sàng hoặc hành trình khách hàng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('723e1dfb-039e-44a7-9211-71e983c94046','eecfe7d7-04d1-4a9a-84dc-1a822a1fc7e8',150,'text','Lượng hóa toàn bộ các tiêu chí mơ hồ thành các con số hoặc hành động quan sát được (SLA thời gian, hành vi cụ thể).',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('32d21182-5fa9-4abe-94fe-e2fdf8a37b66','eecfe7d7-04d1-4a9a-84dc-1a822a1fc7e8',151,'text','Xây dựng kịch bản và bộ quy tắc ứng xử cho các trường hợp ngoại lệ hoặc rủi ro thường gặp.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('92bdfd41-f35f-49b4-badc-58b5048369a9','eecfe7d7-04d1-4a9a-84dc-1a822a1fc7e8',152,'text','**Đầu ra bắt buộc:**- Detail Breakdown Matrix (Ma trận bóc tách chi tiết từng bước làm).  - Quantified Standards Sheet (Bảng tiêu chuẩn lượng hóa hành vi).  - Exception Handling Rules (Bộ quy tắc xử lý tình huống ngoại lệ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('fe30b865-2951-4551-ba3b-027fd7eb5bd0','eecfe7d7-04d1-4a9a-84dc-1a822a1fc7e8',153,'text','**Người phụ trách:** Circle Lead phối hợp chặt chẽ với Trainer và các vai trò trực tiếp nằm trong luồng công việc đó.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e146584e-382a-4de8-97fc-cab01bf79444','eecfe7d7-04d1-4a9a-84dc-1a822a1fc7e8',154,'text','**KPI / tín hiệu theo dõi:**- Tỷ lệ các tiêu chuẩn được lượng hóa thành công (Yêu cầu đạt 100%).  - Mức độ thống nhất và thấu hiểu giống nhau của đội ngũ sau khi bóc tách chi tiết.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('895127a3-272a-4148-9e4d-e99ecfb3542c','05-ung-dung-roadmap','aeb6325e-ff2e-49d3-b688-8c7fa4fd7339',2,'P - Process','p-process',40,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e8a6f120-16f9-4f6a-afc6-be5f42010849','895127a3-272a-4148-9e4d-e99ecfb3542c',155,'text','**Đóng Gói Quy Trình**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('eb7ea06f-3f7f-4414-9d5d-fee4a9871208','895127a3-272a-4148-9e4d-e99ecfb3542c',156,'text','**Mục tiêu của bước này:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('69b92d5e-8f32-40cf-a473-6b9e2164afdd','895127a3-272a-4148-9e4d-e99ecfb3542c',157,'text','Đây là lúc điều đã được làm rõ bắt đầu được chuyển thành SOP, quy trình lặp lại, tài liệu hướng dẫn và logic chuyển giao. Process là bước cực kỳ quan trọng, vì nếu không có quy trình, tổ chức sẽ phụ thuộc quá nhiều vào cá nhân giỏi. Khi đó hệ thống không bền, vì người giỏi nghỉ đi thì chuẩn mực cũng dễ tan theo.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('cf92dde2-fd4c-4d4a-a804-32e6bc2f97e2','895127a3-272a-4148-9e4d-e99ecfb3542c',158,'text','**Dấu hiệu cần thực hiện:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5219156f-ea68-4005-9bd9-6b645709eea0','895127a3-272a-4148-9e4d-e99ecfb3542c',159,'text','Khi các tiêu chuẩn chi tiết đã được màng lọc chuyên môn thông qua và cần được "hóa thạch" thành tài sản trí tuệ vĩnh viễn của phòng khám để chuẩn bị nhân bản hoặc đào tạo.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('682c3a39-295e-4f51-8766-c0b6352697e9','895127a3-272a-4148-9e4d-e99ecfb3542c',160,'text','**Cách thực hiện:**- Văn bản hóa toàn bộ nội dung thành bộ quy trình chuẩn (SOP) theo cấu trúc: Rõ vai trò, rõ bước làm, rõ SLA bàn giao.  - Thiết kế sơ đồ luồng vận hành (Flowchart) trực quan để nhân sự dễ hình dung dòng chảy công việc.  - Số hóa và đóng gói tài liệu lên hệ thống lưu trữ/học tập nội bộ (LMS).',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ce8665b4-7264-4ee9-8bcd-8c5dd365239c','895127a3-272a-4148-9e4d-e99ecfb3542c',161,'text','**Đầu ra bắt buộc:**- SOP Documents (Bộ văn bản quy trình chuẩn hóa của phòng khám).  - Visual Flowchart (Sơ đồ luồng công việc trực quan).  - Training Package (Tài liệu/Video hướng dẫn chuyển giao nội bộ).',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e2f41b1b-949a-4757-84e6-b0c6ed1102c6','895127a3-272a-4148-9e4d-e99ecfb3542c',162,'text','**Người phụ trách:** Trainer (Chuyên viên đào tạo SOP) phối hợp với Thư ký Circle (Secretary) để đóng gói văn bản.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2ef8ecb7-98d7-4196-aa26-a3162715c91c','895127a3-272a-4148-9e4d-e99ecfb3542c',163,'text','**KPI / tín hiệu theo dõi:**- Tỷ lệ các quy trình cốt lõi được văn bản hóa hoàn chỉnh đúng thời hạn.  - Tỷ lệ nhân sự mới có thể tự học và hiểu đúng quy trình qua tài liệu đóng gói.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('b49184b7-6f44-479e-a3e5-5e8efdb276ed','05-ung-dung-roadmap','aeb6325e-ff2e-49d3-b688-8c7fa4fd7339',2,'E -  Enforce','e-enforce',41,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ba27ec47-ddb6-4ecf-9cc0-82862749de9d','b49184b7-6f44-479e-a3e5-5e8efdb276ed',164,'text','**Bảo Đảm Thực Thi**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('15a8232f-431b-40fd-ab55-0d5bfa6bce00','b49184b7-6f44-479e-a3e5-5e8efdb276ed',165,'text','**Mục tiêu của bước này:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('db2b0b07-de3e-4757-8fa9-211e120bb8db','b49184b7-6f44-479e-a3e5-5e8efdb276ed',166,'text','Một quy trình chỉ thật sự có giá trị khi nó được ép vào thực tế bằng checklist, KPI, trách nhiệm, quyền hạn và cơ chế kiểm soát. Enforce không có nghĩa là cứng nhắc vô cảm, mà là tổ chức phải có khả năng bảo vệ chuẩn bằng hành động cụ thể(). Nếu không enforce, SOP sẽ chỉ nằm trên giấy.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c58973b9-af7f-4f19-8cc2-55b4cab42702','b49184b7-6f44-479e-a3e5-5e8efdb276ed',167,'text','**Dấu hiệu cần thực hiện:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1db6c718-d4cc-4782-a518-f6e1d3bbc2f7','b49184b7-6f44-479e-a3e5-5e8efdb276ed',168,'text','Quy trình đã đóng gói xong nhưng nhân sự vẫn làm theo thói quen cũ vô kỷ luật, hoặc hệ thống thiếu công cụ giám sát, nhắc nhở và kiểm tra độ tuân thủ hằng ngày.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e835a158-bcb3-4871-9f2e-06ebc2bb4bed','b49184b7-6f44-479e-a3e5-5e8efdb276ed',169,'text','**Cách thực hiện:**- Cài đặt hệ thống Checklist bắt buộc theo ngày/ca trực tiếp trên phần mềm ERP/CRM hoặc bảng in tại ghế nha.  - Gắn chặt chỉ số tuân thủ quy trình vào khung năng lực và cơ chế đãi ngộ toàn diện của S.T.A.R.S People OS.  - Kích hoạt nhịp kiểm tra ngẫu nhiên và xử lý nghiêm các vi phạm mang tính hệ thống.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('20a44ff0-f9df-402c-abd9-b3a4480da201','b49184b7-6f44-479e-a3e5-5e8efdb276ed',170,'text','**Đầu ra bắt buộc:**- Operational Checklists (Bộ checklist thực thi bắt buộc theo ca/ngày).  - Role Card Updated (Cập nhật trách nhiệm giải trình quy trình vào Thẻ vai trò).  - SOP Compliance Monitor Dashboard (Hệ thống giám sát tỷ lệ tuân thủ).',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a87c2557-77db-4024-bf7c-682baad2a037','b49184b7-6f44-479e-a3e5-5e8efdb276ed',171,'text','**Người phụ trách:** Circle Lead (Marketing/Clinic Manager), Điều dưỡng trưởng phối hợp với Finance & Data Circle để cài đặt chỉ số.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ef29479f-ec6f-45be-ab30-ae7bf2680c99','b49184b7-6f44-479e-a3e5-5e8efdb276ed',172,'text','**KPI / tín hiệu theo dõi:**- **SOP Compliance Rate** (Tỷ lệ tuân thủ quy trình qua kiểm tra checklist phải đạt >95%).  - Tỷ lệ lỗi vận hành phát sinh do nhân sự bỏ qua bước trong checklist.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('b3c7d89a-66ea-4e2f-8f98-236bdf555b32','05-ung-dung-roadmap','aeb6325e-ff2e-49d3-b688-8c7fa4fd7339',2,'N - Normalize','n-normalize',42,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a00d7e22-fe00-4fdb-a6fa-842c372be916','b3c7d89a-66ea-4e2f-8f98-236bdf555b32',173,'text','**Bình Thường Hóa Vận Hành**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('64850450-1c01-45ad-b9f4-4daaf1296c68','b3c7d89a-66ea-4e2f-8f98-236bdf555b32',174,'text','**Mục tiêu của bước này:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f2717b37-e35b-4c3e-b27e-35e9aa5a52ae','b3c7d89a-66ea-4e2f-8f98-236bdf555b32',175,'text','Đây là đích đến của toàn bộ quá trình DEEPEN(). Khi một chuẩn đã được làm đủ rõ, đủ tốt, đủ lặp lại và đủ được thực thi, nó không còn là “việc đặc biệt nữa”, mà trở thành cách làm mặc định của toàn tổ chức. Normalize là lúc chuẩn mực không cần phải nhắc quá nhiều vì nó đã đi vào thói quen, phản xạ và văn hóa làm việc.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('90733380-7657-4b86-96df-f588092e0f73','b3c7d89a-66ea-4e2f-8f98-236bdf555b32',176,'text','**Dấu hiệu cần thực hiện:** Khi quy trình mới đã chạy ổn định, nhân sự không còn phản kháng và hệ thống cần được pháp lý hóa hoàn toàn để đồng hóa vào lõi văn hóa SKY.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('529a6930-5ac9-4bb6-880c-35ee0c0b9f6e','b3c7d89a-66ea-4e2f-8f98-236bdf555b32',177,'text','**Cách thực hiện:**- Thư ký chính thức khóa quy trình thành Chính sách (Policy) vĩnh viễn và ghi nhận vào hệ thống **Governance Logbook**.  - Đưa tiêu chuẩn hành vi của quy trình này vào bộ màng lọc tuyển dụng nhân sự mới và đánh giá văn hóa tổ chức định kỳ.  - Chuyển giao toàn quyền tự quản luồng việc đó cho các vai trò con tự chủ thực thi thông qua cơ chế S3 Holacracy Lite.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('51ec4b39-7f7e-476b-acd9-986630a15033','b3c7d89a-66ea-4e2f-8f98-236bdf555b32',178,'text','**Đầu ra bắt buộc:**- Governance Logbook Updated (Sổ tay quản trị được cập nhật chính thức).  - Default Workplace Habit Model (Mô hình phản xạ hành vi mặc định tại phòng khám).  - Logbook Decision Records (Nhật ký ghi nhận pháp lý cấu trúc).',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f622e951-2e9a-42db-a213-fede3c04af47','b3c7d89a-66ea-4e2f-8f98-236bdf555b32',179,'text','**Người phụ trách:** Thư ký Circle (Secretary) phối hợp với Ban chiến lược (Core Circle) và khối bộ phận văn hóa (People & Culture Circle).',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5fe8524c-e295-4329-bb09-d7fdc3cfd148','b3c7d89a-66ea-4e2f-8f98-236bdf555b32',180,'text','**KPI / tín hiệu theo dõi:**- Tỷ lệ tái diễn lỗi hệ thống do quên hoặc sai quy trình (Chạm ngưỡng 0%).  - Tỷ lệ nhân sự tự giác thực hiện đúng chuẩn 100% mà không cần cấp quản lý đứng giám sát tại chỗ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('eefcac66-5e40-476d-9d03-c97e65bfff23','05-ung-dung-roadmap',NULL,1,'5.5 MATURE','55-mature',43,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('5c66bd6b-9f9e-4863-a91d-ee84a301e760','05-ung-dung-roadmap','eefcac66-5e40-476d-9d03-c97e65bfff23',2,'M - Momentum','m-momentum',44,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5a5f5471-f3e1-485f-ba24-0e57372df109','5c66bd6b-9f9e-4863-a91d-ee84a301e760',181,'text','**Mục tiêu của bước này**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1e9895ad-7a4a-4945-a5d7-72a579bd6d82','5c66bd6b-9f9e-4863-a91d-ee84a301e760',182,'text','Momentum là tạo đà phát triển để hệ thống không vận hành rời rạc hoặc phải khởi động lại quá nhiều lần. Khi có momentum, các nỗ lực nhỏ sẽ cộng dồn tốt hơn và tổ chức có cảm giác “tiến lên” liên tục.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6c43a9c9-15a0-4caf-a710-eadb4297adf8','5c66bd6b-9f9e-4863-a91d-ee84a301e760',183,'image',NULL,'book/05-ung-dung-roadmap/e5033342-b8da-42e7-86d1-48ebb7e30c6d-img06.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('47521cda-036e-43b5-aadb-ec73241f2306','5c66bd6b-9f9e-4863-a91d-ee84a301e760',184,'text','**Dấu hiệu cần thực hiện**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('165a52e1-3137-4002-afe6-759d96c3934d','5c66bd6b-9f9e-4863-a91d-ee84a301e760',185,'text','Thực hiện khi team bị đứt mạch triển khai, dự án hay dừng giữa chừng, hoặc mỗi chu kỳ đều phải bắt đầu lại từ đầu. Đây là tầng nền để hệ thống có lực kéo thay vì chỉ có ý chí.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('457d5aa5-5433-446e-961d-703b63ff32de','5c66bd6b-9f9e-4863-a91d-ee84a301e760',186,'text','**Cách thực hiện**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('8274006b-46ef-4e9b-bb09-68fffc0f66e5','5c66bd6b-9f9e-4863-a91d-ee84a301e760',187,'text','- Xác định các hoạt động tạo đà rõ nhất cho hệ thống.- Duy trì nhịp làm việc đều, ít ngắt quãng.- Ưu tiên các việc tạo hiệu ứng cộng dồn thay vì chỉ xử lý việc lẻ tẻ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a9863880-ca90-4445-a4aa-466386328ea2','5c66bd6b-9f9e-4863-a91d-ee84a301e760',188,'text','**Đầu ra bắt buộc**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2655c16e-e9e8-4767-a5ba-aa2ea694b5f2','5c66bd6b-9f9e-4863-a91d-ee84a301e760',189,'text','- Momentum map.- Danh sách hoạt động tạo đà.- Nhịp triển khai cố định.',NULL,NULL,NULL,NULL,NULL);
