INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('13848ca9-e0fa-42db-9501-ff33120002b0','5c66bd6b-9f9e-4863-a91d-ee84a301e760',192,'text','Phối hợp: các owner module liên quan.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c0bff6d0-cc1d-487f-b544-a7fd5f33b1ef','5c66bd6b-9f9e-4863-a91d-ee84a301e760',193,'text','**KPI / tín hiệu theo dõi**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('3d337066-54f2-45f9-9227-145e88ff3ecc','5c66bd6b-9f9e-4863-a91d-ee84a301e760',194,'text','- Tỷ lệ công việc được duy trì liên tục.- Số chu kỳ không bị ngắt quãng.- Mức độ tích lũy kết quả theo thời gian.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a5fde9fe-7004-465e-8dbf-f87f23681980','5c66bd6b-9f9e-4863-a91d-ee84a301e760',195,'image',NULL,'book/05-ung-dung-roadmap/1ba8b817-917f-4f5f-9cc3-301694491fcb-img07.png','image.png','image/png','image.png',NULL);
