INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1d309cbf-0b12-4009-aee6-fa05b5e534d3','71aa5eac-f3be-4fe7-a1ec-2b9ff23543a7',196,'text','**Mục tiêu của bước này**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('33e73a66-3f09-4510-92fe-945717217382','71aa5eac-f3be-4fe7-a1ec-2b9ff23543a7',197,'text','Attune là chỉnh nhịp mục tiêu, con người và cơ chế để toàn hệ cùng tần số. Bước này giúp chiến lược, vai trò và nhịp vận hành không đi lệch nhau.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2970ce1a-ba2c-4c7b-8752-0736b8090fee','71aa5eac-f3be-4fe7-a1ec-2b9ff23543a7',198,'text','**Dấu hiệu cần thực hiện**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('311271b6-7640-4628-81e5-6539d742f24d','71aa5eac-f3be-4fe7-a1ec-2b9ff23543a7',199,'text','Thực hiện khi mục tiêu một đằng, con người một nẻo, hoặc mỗi bộ phận làm theo nhịp riêng khiến hệ thống mất đồng bộ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e47c1d40-6c82-4486-a189-6fa5339c0514','71aa5eac-f3be-4fe7-a1ec-2b9ff23543a7',200,'text','**Cách thực hiện**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('500325a1-f3c8-488d-a4da-88c7390db123','71aa5eac-f3be-4fe7-a1ec-2b9ff23543a7',201,'text','- So khớp mục tiêu với role, KPI và lịch vận hành.- Chỉnh lại cadence họp, báo cáo và bàn giao.- Làm rõ nhịp nào là nhịp chung của tổ chức.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('8a2152ba-6f4d-4331-a020-f3bad814acda','71aa5eac-f3be-4fe7-a1ec-2b9ff23543a7',202,'text','**Đầu ra bắt buộc**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f176db2e-79a7-4546-a6cd-13c5a4af017e','71aa5eac-f3be-4fe7-a1ec-2b9ff23543a7',203,'text','- Operating rhythm.',NULL,NULL,NULL,NULL,NULL);
