INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('aafcf1bf-4900-4dd7-8707-52554709d7a5','71aa5eac-f3be-4fe7-a1ec-2b9ff23543a7',205,'text','Chính: Founder hoặc Clinic Manager.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('56d728a1-a11c-4eea-a723-bc6074dc6388','71aa5eac-f3be-4fe7-a1ec-2b9ff23543a7',206,'text','Phối hợp: Data Lead, People Lead và các trưởng bộ phận.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4154275d-4c57-47e9-9ce8-f8a86c2be9e2','71aa5eac-f3be-4fe7-a1ec-2b9ff23543a7',207,'text','**KPI / tín hiệu theo dõi**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4cd74d7f-14fc-451f-8dac-4322a1a928dd','71aa5eac-f3be-4fe7-a1ec-2b9ff23543a7',208,'text','- Tỷ lệ mục tiêu được hiểu giống nhau.- Tỷ lệ team bám đúng nhịp chung.- Số điểm lệch được phát hiện và chỉnh lại.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('3409d790-db34-4508-b39e-13c181f3871b','71aa5eac-f3be-4fe7-a1ec-2b9ff23543a7',209,'image',NULL,'book/05-ung-dung-roadmap/edaf0093-a016-4611-8517-a2d710941454-img08.png','image.png','image/png','image.png',NULL);
