INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('57df46f5-8121-4664-9692-41cefcae81d8','3d71dde6-640c-4950-abbd-79fce423cdb1',210,'text','**Mục tiêu của bước này**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2a29867b-3528-4926-b0b6-8133f5d64773','3d71dde6-640c-4950-abbd-79fce423cdb1',211,'text','Trust là xây niềm tin bằng tính nhất quán, tiêu chuẩn rõ và trải nghiệm thật trong vận hành. Niềm tin là nền để con người tin nhau, tin quy trình và tin năng lực chung của tổ chức.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('37b90ed8-4d16-4361-907e-3339acd374de','3d71dde6-640c-4950-abbd-79fce423cdb1',212,'text','**Dấu hiệu cần thực hiện**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('246d646f-cb2a-40e6-8639-bed181bf96e6','3d71dde6-640c-4950-abbd-79fce423cdb1',213,'text','Thực hiện khi hệ thống có nhiều lời hứa nhưng trải nghiệm chưa đều, hoặc khi nội bộ còn thiếu tin cậy vì tiêu chuẩn chưa rõ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e2179f04-1282-41e0-8320-aea6c33183b4','3d71dde6-640c-4950-abbd-79fce423cdb1',214,'text','**Cách thực hiện**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a1195639-2b83-4c90-852a-ead2e0d59a9d','3d71dde6-640c-4950-abbd-79fce423cdb1',215,'text','- Chuẩn hóa SOP, tiêu chuẩn và cách kiểm tra.- Làm đúng đều trong thời gian đủ dài.- Ghi nhận và củng cố các điểm tạo niềm tin nội bộ và với khách hàng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2f502ab8-2376-4890-96f3-b301351261cf','3d71dde6-640c-4950-abbd-79fce423cdb1',216,'text','**Đầu ra bắt buộc**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('810bbd2a-bba1-4cf0-be41-745f23be4b47','3d71dde6-640c-4950-abbd-79fce423cdb1',217,'text','- Trust standard.- SOP / checklist đã chuẩn hóa.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2a8548ec-cfe9-4466-8d37-42eb68fd1868','3d71dde6-640c-4950-abbd-79fce423cdb1',218,'text','**Người phụ trách**',NULL,NULL,NULL,NULL,NULL);
