INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ce12b0f2-b579-4a3f-b815-32437527a6d3','3d71dde6-640c-4950-abbd-79fce423cdb1',220,'text','Phối hợp: toàn bộ team vận hành và dịch vụ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6051e086-be25-4a24-9cc9-8cc5e3dfbbd0','3d71dde6-640c-4950-abbd-79fce423cdb1',221,'text','**KPI / tín hiệu theo dõi**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0af7bf02-8672-4f3f-b76a-57c14da64e99','3d71dde6-640c-4950-abbd-79fce423cdb1',222,'text','- Tỷ lệ tuân thủ tiêu chuẩn.- Tỷ lệ sai lệch giảm dần.- Mức độ tin cậy từ khách hàng và nội bộ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('66644e78-700f-4b00-a396-2eb24c5dd749','05-ung-dung-roadmap','eefcac66-5e40-476d-9d03-c97e65bfff23',2,'U - Unite','u-unite',47,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9eda8dee-4912-4782-9822-abf9348d654a','66644e78-700f-4b00-a396-2eb24c5dd749',223,'text','**Mục tiêu của bước này**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('340d4dd9-fa0a-47f8-9a6e-5588cb8911cd','66644e78-700f-4b00-a396-2eb24c5dd749',224,'text','Unite là gắn kết vai trò, bộ phận và nguồn lực thành một khối phối hợp hiệu quả. Khi unite tốt, các bộ phận không hoạt động như ốc đảo mà cùng đẩy về một hướng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('3b4820c3-071c-4fb9-a9d9-c61f5f25015d','66644e78-700f-4b00-a396-2eb24c5dd749',225,'text','**Dấu hiệu cần thực hiện**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7b53e837-9e44-4321-94d6-dc24c3ba0bf6','66644e78-700f-4b00-a396-2eb24c5dd749',226,'text','Thực hiện khi có tình trạng đổ lỗi giữa bộ phận, bàn giao kém, hoặc mỗi phòng ban tối ưu riêng mà không tối ưu toàn hệ thống.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('44b33bf9-bf80-4362-a651-bf6333421ab2','66644e78-700f-4b00-a396-2eb24c5dd749',227,'text','**Cách thực hiện**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('bf93ba54-e924-4960-92b0-c6cf3142978b','66644e78-700f-4b00-a396-2eb24c5dd749',228,'text','- Xác định điểm bàn giao giữa các bộ phận.- Làm rõ owner, phối hợp và trách nhiệm chung.- Thiết kế nhịp họp và nhịp phối hợp liên phòng ban.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b9e0cf94-6202-4624-b751-cd6316e910b6','66644e78-700f-4b00-a396-2eb24c5dd749',229,'text','**Đầu ra bắt buộc**',NULL,NULL,NULL,NULL,NULL);
