INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ca84f4c4-9a7a-433e-b3d5-55b623ce087b','a5e5889a-97c2-4fcd-bd0c-e5d88a0fc7fe',236,'text','**Mục tiêu của bước này**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('58d0175e-fda9-4214-947c-4299f78dec8e','a5e5889a-97c2-4fcd-bd0c-e5d88a0fc7fe',237,'text','Refine là tinh chỉnh quy trình, cấu trúc và cách làm để giảm ma sát và tăng độ sắc nét của hệ thống. Bước này giúp tổ chức bớt nặng nề, bớt rối và bớt lãng phí năng lượng.',NULL,NULL,NULL,NULL,NULL);
