INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d4713b68-1c51-469b-9ad3-3a3b47d15135','a5e5889a-97c2-4fcd-bd0c-e5d88a0fc7fe',239,'text','Thực hiện khi quy trình đã có nhưng còn cồng kềnh, chậm, nhiều bước thừa hoặc còn phụ thuộc vào cá nhân.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7e182c69-bf19-4779-82f7-a07e0057f7d3','a5e5889a-97c2-4fcd-bd0c-e5d88a0fc7fe',240,'text','**Cách thực hiện**',NULL,NULL,NULL,NULL,NULL);
