INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a78d5a2f-5bac-439a-990d-2c4c45d4afb1','07e351a6-4f02-41d1-9c24-8a029bfb0a01',251,'text','**Mục tiêu của bước này**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('44594c7f-385d-469c-b4a6-ead580b01cb4','07e351a6-4f02-41d1-9c24-8a029bfb0a01',252,'text','Elevate là nâng cấp chuẩn vận hành, năng lực đội ngũ và chất lượng tăng trưởng lên tầng cao hơn. Đây là đích đến của MATURE: không chỉ ổn định hơn mà còn cao hơn về chuẩn và sâu hơn về năng lực.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('bc6c08c5-97a9-4d57-81a9-f4feb0de7848','07e351a6-4f02-41d1-9c24-8a029bfb0a01',253,'text','**Dấu hiệu cần thực hiện**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('54309d1b-7e4b-412c-9493-98a1e946f85c','07e351a6-4f02-41d1-9c24-8a029bfb0a01',254,'text','Thực hiện khi hệ thống đã ổn định tương đối, khi cần scale, hoặc khi muốn chuyển từ “làm tốt” sang “làm xuất sắc và nhân bản được”.',NULL,NULL,NULL,NULL,NULL);
