INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('898b0cfa-9083-40f1-95b3-f872d0ff2cb3','91c4ca56-36db-45a9-a11d-a92d0a91b8f7',264,'text','**Mục tiêu của bước này**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('719424dc-cf91-48ea-9b6a-85ff719a2cd5','91c4ca56-36db-45a9-a11d-a92d0a91b8f7',265,'text','Anchor là neo mục tiêu chung, giữ cho toàn bộ hệ thống không trôi khỏi định hướng cốt lõi. Trong Dental OS, Anchor thường là Strategy OS, core service, mục tiêu tăng trưởng và ưu tiên vận hành của giai đoạn hiện tại.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b812ae9b-6032-483d-a72c-bcc3f5aea37c','91c4ca56-36db-45a9-a11d-a92d0a91b8f7',266,'text','**Dấu hiệu cần thực hiện**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2a59c339-5e95-4ffc-b24b-f47c02b28f89','91c4ca56-36db-45a9-a11d-a92d0a91b8f7',267,'text','Cần Anchor khi các bộ phận bắt đầu ưu tiên khác nhau, quyết định bị kéo bởi áp lực ngắn hạn, hoặc team không còn cùng nhìn về một đích.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b8a4c196-76ae-4d10-85ea-4d6f1da0511f','91c4ca56-36db-45a9-a11d-a92d0a91b8f7',268,'text','**Cách thực hiện**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1dfa7c5c-1998-4998-8d31-84a379ba2a57','91c4ca56-36db-45a9-a11d-a92d0a91b8f7',269,'text','- Chốt một mục tiêu chiến lược rõ cho kỳ hiện tại.- Gắn mục tiêu đó vào dashboard, OKR và meeting rhythm.- Truyền cùng một anchor cho toàn bộ role card và module liên quan.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('29d51e75-dc69-4f01-ac31-1b823ca3f1c6','91c4ca56-36db-45a9-a11d-a92d0a91b8f7',270,'text','**Đầu ra bắt buộc**',NULL,NULL,NULL,NULL,NULL);
