INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('08b1ff88-6539-472f-9cb6-1d7a4d83aec7','91c4ca56-36db-45a9-a11d-a92d0a91b8f7',272,'text','**Người phụ trách**
Founder / CEO / Chủ phòng khám, phối hợp với Strategy Lead, Finance Lead và Data Lead.',NULL,NULL,NULL,NULL,NULL);
