INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d9972d1f-5ba0-4b37-8f67-6fe44a8a98ba','91c4ca56-36db-45a9-a11d-a92d0a91b8f7',274,'text','- Mức độ rõ của mục tiêu chung.- Tỷ lệ team hiểu cùng một ưu tiên.- Tỷ lệ quyết định bám đúng chiến lược.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('ad3dbe00-5331-461e-8e8a-8fc9258ad3cf','05-ung-dung-roadmap','8ad6a296-5686-4569-a27e-123cb5c26c00',2,'L - Link','l-link',52,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('8a7322cb-b078-486f-9445-6c5773d62493','ad3dbe00-5331-461e-8e8a-8fc9258ad3cf',275,'text','**Mục tiêu của bước này**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f5a29aa0-3a00-4b28-a604-82975834e275','ad3dbe00-5331-461e-8e8a-8fc9258ad3cf',276,'text','Link là nối con người, dữ liệu, công cụ và nguồn lực để hệ thống không vận hành rời rạc. Nó là lớp kết nối giữa các OS, role card và dashboard.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('90c69f2a-4bb5-46b0-91ce-3a926f41a8d6','ad3dbe00-5331-461e-8e8a-8fc9258ad3cf',277,'text','**Dấu hiệu cần thực hiện**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('00160cb5-e5f1-4a02-9e68-44706754d319','ad3dbe00-5331-461e-8e8a-8fc9258ad3cf',278,'text','Cần Link khi bàn giao giữa các bộ phận bị đứt, thông tin phải hỏi lại nhiều lần, hoặc dữ liệu nằm rời rạc ở nhiều nơi.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('bd2d6819-3db2-4c75-96aa-4cd45cfa8727','ad3dbe00-5331-461e-8e8a-8fc9258ad3cf',279,'text','**Cách thực hiện**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c0646b64-7851-4144-aedc-18991400cd2e','ad3dbe00-5331-461e-8e8a-8fc9258ad3cf',280,'text','- Chuẩn hóa handover giữa các vai trò.- Đồng bộ CRM, checklist, dashboard và file dùng chung.- Quy định rõ ai gửi, ai nhận, ai xác nhận.',NULL,NULL,NULL,NULL,NULL);
