INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1b926dcd-8b23-45bf-a923-4ed531f5c0be','be6bf917-0de9-4249-888b-758ca3e32c00',287,'text','**Mục tiêu của bước này**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7c98a834-ccb0-4c40-aae5-af57bdabd026','be6bf917-0de9-4249-888b-758ca3e32c00',288,'text','Integrate là tích hợp quy trình, vai trò và nhịp vận hành thành một hệ thống liền mạch. Đây là tầng làm cho kế hoạch, trách nhiệm và công cụ chạy cùng nhau.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7f2e2f7d-3444-4c34-a0ad-49267d7e0857','be6bf917-0de9-4249-888b-758ca3e32c00',289,'text','**Dấu hiệu cần thực hiện**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('15f632e2-b71b-4aad-a95f-042050f5cc82','be6bf917-0de9-4249-888b-758ca3e32c00',290,'text','Cần Integrate khi SOP có nhưng team vẫn làm lệch, KPI có nhưng không phản ánh đúng hành vi, hoặc các module vẫn chạy như các mảnh ghép riêng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('8e2cd216-f41c-4d42-84d7-f7382fb93384','be6bf917-0de9-4249-888b-758ca3e32c00',291,'text','**Cách thực hiện**',NULL,NULL,NULL,NULL,NULL);
