INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e0cbae4d-86ab-4d94-a512-4343c5245f70','be6bf917-0de9-4249-888b-758ca3e32c00',298,'text','- Tỷ lệ quy trình chạy đúng từ đầu đến cuối.- Mức giảm lỗi do đứt gãy giữa các bước.- Mức độ đồng nhất giữa kế hoạch và thực thi.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('45720bf9-f208-4db5-8469-9c935e2864d2','05-ung-dung-roadmap','8ad6a296-5686-4569-a27e-123cb5c26c00',2,'G - Govern','g-govern',54,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('eb3835c8-19c8-4e25-a9b9-37594e5c50e1','45720bf9-f208-4db5-8469-9c935e2864d2',299,'text','**Mục tiêu của bước này**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ee991f55-fa0e-4b1e-9761-f43a3dfb3376','45720bf9-f208-4db5-8469-9c935e2864d2',300,'text','Govern là thiết lập cơ chế quản trị, phân quyền, trách nhiệm và nhịp họp để hệ thống đi đúng hướng. Đây là lớp giữ cho alignment không chỉ nằm trên sơ đồ mà đi vào vận hành thật.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f6a686d7-c45a-44ec-9889-8969dc29ca01','45720bf9-f208-4db5-8469-9c935e2864d2',301,'text','**Dấu hiệu cần thực hiện**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ca0275c5-dfcb-491f-891b-b3edd4917bec','45720bf9-f208-4db5-8469-9c935e2864d2',302,'text','Cần Govern khi ai cũng làm nhưng không ai chịu trách nhiệm cuối, hoặc khi team cần nhiều nhắc nhở mà vẫn không giữ được nhịp.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b11a4761-dd8c-4d47-9fdc-96f427d86317','45720bf9-f208-4db5-8469-9c935e2864d2',303,'text','**Cách thực hiện**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('567eec28-eb5d-479e-92d2-80527c4bc624','45720bf9-f208-4db5-8469-9c935e2864d2',304,'text','- Thiết kế RACI hoặc accountability map.- Chốt meeting rhythm và decision owner.- Dùng alert rule để xử lý lệch chuẩn sớm.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ec5d8dc5-006c-4323-9b83-c776435e4f44','45720bf9-f208-4db5-8469-9c935e2864d2',305,'text','**Đầu ra bắt buộc**',NULL,NULL,NULL,NULL,NULL);
