INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('28646f16-5088-41d3-9b51-8c94b3a6ce7a','45720bf9-f208-4db5-8469-9c935e2864d2',307,'text','**Người phụ trách**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f10557b8-09af-4ee3-b1b4-3a76ab17994b','45720bf9-f208-4db5-8469-9c935e2864d2',308,'text','Founder / CEO, Clinic Manager, People Lead và Data Lead.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9133f24c-9eec-42a8-b4e7-a0ab32b232ba','45720bf9-f208-4db5-8469-9c935e2864d2',309,'text','**KPI / tín hiệu theo dõi**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5168567b-3172-4a60-ab00-476d84296db6','45720bf9-f208-4db5-8469-9c935e2864d2',310,'text','- Tỷ lệ quyết định có owner rõ.- Tỷ lệ họp ra được action.- Tỷ lệ issue được xử lý đúng hạn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('7c31d9f7-e0c6-4696-a0bb-480edbf35b3f','05-ung-dung-roadmap','8ad6a296-5686-4569-a27e-123cb5c26c00',2,'N - Narrow','n-narrow',55,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1f3c7698-f34b-4ce6-8eb2-b639b218468d','7c31d9f7-e0c6-4696-a0bb-480edbf35b3f',311,'text','**Mục tiêu của bước này**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5ab94ddf-d1a5-44f5-b749-8106fcb6502c','7c31d9f7-e0c6-4696-a0bb-480edbf35b3f',312,'text','Narrow là thu hẹp khoảng lệch giữa mục tiêu và thực tế, giữa kế hoạch và thực thi, giữa các bộ phận trong hệ thống. Đây là đích đến của ALIGN: giảm lệch liên tục cho đến khi hệ thống khớp hơn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c4d3d7ed-4b29-41e6-954c-cad66a764fef','7c31d9f7-e0c6-4696-a0bb-480edbf35b3f',313,'text','**Dấu hiệu cần thực hiện**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('33332dc7-4e57-4cc6-b912-c563cb08c3b6','7c31d9f7-e0c6-4696-a0bb-480edbf35b3f',314,'text','Cần Narrow khi kế hoạch tốt nhưng kết quả thấp hơn kỳ vọng, hoặc khi cùng một vấn đề lặp lại nhiều lần giữa các vòng review.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5d2b37fd-717e-4666-985b-d96d64145524','7c31d9f7-e0c6-4696-a0bb-480edbf35b3f',315,'text','**Cách thực hiện**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ec307e11-6016-49af-acac-da6717162311','7c31d9f7-e0c6-4696-a0bb-480edbf35b3f',316,'text','- So sánh mục tiêu với kết quả theo chu kỳ.- Ghi rõ nguyên nhân lệch và action sửa.- Cập nhật SOP, role hoặc nhịp vận hành khi lệch lặp lại.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('85e98c03-65fe-4cc6-bc45-09c8b6679af5','7c31d9f7-e0c6-4696-a0bb-480edbf35b3f',317,'text','**Đầu ra bắt buộc**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('3e086e0d-3563-4dd5-ac03-ad5ee6406253','7c31d9f7-e0c6-4696-a0bb-480edbf35b3f',318,'text','- Gap analysis.- Action tracker.- Update log cho SOP / role / rhythm.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7080d645-a402-43d8-966d-20a321e8ca12','7c31d9f7-e0c6-4696-a0bb-480edbf35b3f',319,'text','**Người phụ trách**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('97120666-ee8f-4c2c-bd63-7247a5ebbf8c','7c31d9f7-e0c6-4696-a0bb-480edbf35b3f',320,'text','Data Lead, owner module và founder / manager tùy mức độ lệch.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('79105bb1-c26d-4e3a-b033-5c89217e03e9','7c31d9f7-e0c6-4696-a0bb-480edbf35b3f',321,'text','**KPI / tín hiệu theo dõi**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('dafa4f0e-9dee-4de2-9b74-b22cfac40c80','7c31d9f7-e0c6-4696-a0bb-480edbf35b3f',322,'text','- Mức độ lệch giữa plan và actual giảm dần.- Số issue lặp lại giảm.- Tốc độ cải tiến qua từng vòng review tăng.',NULL,NULL,NULL,NULL,NULL);
