INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('47b3a273-7492-482e-93f1-a58fa5f675e6','a5ee9f6c-4f45-4e1d-8cdf-00223bbcf73f',323,'text','**Mục tiêu của bước này**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('95aa96a2-b4a4-435b-b023-ea90bc8f3826','a5ee9f6c-4f45-4e1d-8cdf-00223bbcf73f',324,'text','Proliferate là sinh sôi và lan rộng giá trị theo cấp số nhân để mỗi kết quả tốt tạo ra thêm tác động mới, người dùng mới và cơ hội mới. Trong Dental OS, tầng này gắn mạnh với review, testimonial, referral và trust assets.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('3f4fa920-6710-4ae5-a801-a037e06f6df1','a5ee9f6c-4f45-4e1d-8cdf-00223bbcf73f',325,'text','**Dấu hiệu cần thực hiện**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9f3a6d5b-1cba-40ea-8335-dca87b4fe5ed','a5ee9f6c-4f45-4e1d-8cdf-00223bbcf73f',326,'text','Cần Proliferate khi hệ thống đã tạo ra kết quả tốt nhưng giá trị đó chưa được lan rộng thành nhiều vòng tác động khác.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('40857783-3b20-42f8-a9f9-b6b27f0cbf95','a5ee9f6c-4f45-4e1d-8cdf-00223bbcf73f',327,'text','**Cách thực hiện**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('41ce08f9-bf35-447e-bd17-bf3737a433ed','a5ee9f6c-4f45-4e1d-8cdf-00223bbcf73f',328,'text','- Biến kết quả tốt thành case, review, testimonial và nội dung.- Đưa tài sản tốt quay lại nuôi marketing, sales và trust.- Thiết kế cơ chế để một kết quả sinh ra nhiều đầu ra kế tiếp.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1796ae95-dc36-41c7-aa8f-8a04c67607a5','a5ee9f6c-4f45-4e1d-8cdf-00223bbcf73f',329,'text','**Đầu ra bắt buộc**',NULL,NULL,NULL,NULL,NULL);
