INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6f7137d4-27f7-4c93-9e96-09d9bc26a217','74197ab9-b933-421e-b3d1-26513fc26279',335,'text','**Mục tiêu của bước này**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('da5926f6-05ca-475f-80c4-4eced33f67ab','74197ab9-b933-421e-b3d1-26513fc26279',336,'text','Reinvest là tái đầu tư thành quả tốt trở lại vào con người, quy trình, nội dung và hạ tầng. Đây là cách biến tăng trưởng ngắn hạn thành nền tảng dài hạn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a78998d9-4e6b-4fff-bbec-6cda0eb45648','74197ab9-b933-421e-b3d1-26513fc26279',337,'text','**Dấu hiệu cần thực hiện**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('8a27c5a6-9b9b-45b0-b42b-8e81a476c259','74197ab9-b933-421e-b3d1-26513fc26279',338,'text','Cần Reinvest khi hệ thống có kết quả tốt nhưng không tiếp tục mạnh lên, vì phần thành quả chưa được bơm ngược trở lại hệ thống.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('3c33c764-86f8-4782-b01f-1da15af99702','74197ab9-b933-421e-b3d1-26513fc26279',339,'text','**Cách thực hiện**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('824af45c-1961-4223-a83a-6ba9c01dfaa0','74197ab9-b933-421e-b3d1-26513fc26279',340,'text','- Tái đầu tư vào đào tạo, SOP, dashboard và hạ tầng vận hành.- Tái đầu tư vào content, community và trust assets.- Dùng một phần lợi nhuận để nâng cấp năng lực lõi.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1d021614-deff-463a-af1e-58da084ee139','74197ab9-b933-421e-b3d1-26513fc26279',341,'text','**Đầu ra bắt buộc**',NULL,NULL,NULL,NULL,NULL);
