INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('47945995-863c-4843-8a9f-763b3aeaa4d6','74197ab9-b933-421e-b3d1-26513fc26279',343,'text','**Người phụ trách**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2674d69b-b72a-43c3-890c-13cde5a74bde','74197ab9-b933-421e-b3d1-26513fc26279',344,'text','Founder / CEO, Finance Lead, People Lead và Data Lead.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2121bad4-b1ef-43e6-b50e-597160a5aadc','74197ab9-b933-421e-b3d1-26513fc26279',345,'text','**KPI / tín hiệu theo dõi**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7fd39268-85e0-4c9f-80ba-201890ff5771','74197ab9-b933-421e-b3d1-26513fc26279',346,'text','- Tỷ lệ lợi nhuận được tái đầu tư.- Số cải tiến được tài trợ.- Năng lực đội ngũ tăng sau tái đầu tư.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('767a18a7-057c-4f28-bdf3-7bc6f1afa221','05-ung-dung-roadmap','17c8a3f3-51a2-480b-8cb4-b3b1634715ec',2,'O - Optimize','o-optimize',59,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('44069873-9ace-4838-ace0-c092844b3ddd','767a18a7-057c-4f28-bdf3-7bc6f1afa221',347,'text','**Mục tiêu của bước này**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('65652841-1ae5-4b35-9afb-e2d2de16ea63','767a18a7-057c-4f28-bdf3-7bc6f1afa221',348,'text','Optimize là tối ưu liên tục để giảm ma sát và tăng hiệu suất của toàn hệ thống. Bước này giúp tổ chức nhẹ hơn ở chỗ nặng, nhanh hơn ở chỗ chậm và rõ hơn ở chỗ còn mù.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('204485a0-92d2-44b6-ada5-0ef3139a3cda','767a18a7-057c-4f28-bdf3-7bc6f1afa221',349,'text','**Dấu hiệu cần thực hiện**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f0ee4b58-5fde-43b1-83ae-baac148de46d','767a18a7-057c-4f28-bdf3-7bc6f1afa221',350,'text','Cần Optimize khi quy trình còn rườm rà, chi phí còn cao, thời gian xử lý còn chậm hoặc KPI chưa phản ánh đúng hành vi vận hành.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9e2296c6-8dcf-4e0c-b5af-06327a6d4e2a','767a18a7-057c-4f28-bdf3-7bc6f1afa221',351,'text','**Cách thực hiện**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('27100010-b3dd-49d9-819c-908a8c693c72','767a18a7-057c-4f28-bdf3-7bc6f1afa221',352,'text','- Rà lại workflow, KPI và dashboard định kỳ.- Loại bỏ bước thừa và chỗ gây đứt gãy.- Tối ưu bằng dữ liệu thay vì cảm tính.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d31ab66c-a669-4105-996e-4bd2414f453f','767a18a7-057c-4f28-bdf3-7bc6f1afa221',353,'text','**Đầu ra bắt buộc**',NULL,NULL,NULL,NULL,NULL);
