INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('132c6b08-582a-4247-87c0-8810d6d95547','767a18a7-057c-4f28-bdf3-7bc6f1afa221',355,'text','**Người phụ trách**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d43aaffa-244d-496d-a36d-131b051854fb','767a18a7-057c-4f28-bdf3-7bc6f1afa221',356,'text','Operations Lead, Data Lead, owner từng module.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1933ee43-35c0-4e7a-8951-e08500f70c0c','767a18a7-057c-4f28-bdf3-7bc6f1afa221',357,'text','**KPI / tín hiệu theo dõi**',NULL,NULL,NULL,NULL,NULL);
