INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('8a1ac06d-b116-4e1b-887f-2f2c0463f22d','05-ung-dung-roadmap','17c8a3f3-51a2-480b-8cb4-b3b1634715ec',2,'S - Scale','s-scale',60,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4c29f6fd-76aa-4f33-916a-9b11a86a5c47','8a1ac06d-b116-4e1b-887f-2f2c0463f22d',359,'text','**Mục tiêu của bước này**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1d9dcb3a-b9cd-43e0-8918-2ee4086e3cc1','8a1ac06d-b116-4e1b-887f-2f2c0463f22d',360,'text','Scale là mở rộng có kiểm soát khi hệ thống đã đủ chắc, đủ rõ và đủ bền. Đây là bước mở rộng đúng lúc và đúng nền, không phải mở rộng bằng mọi giá.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5d5a0a8b-c2fb-494d-adaf-08f4e208a0ef','8a1ac06d-b116-4e1b-887f-2f2c0463f22d',361,'text','**Dấu hiệu cần thực hiện**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('cf1b9fc1-5798-4d7b-bebf-39479684786d','8a1ac06d-b116-4e1b-887f-2f2c0463f22d',362,'text','Cần Scale khi mô hình đã ổn định, demand đủ tốt và hệ thống có thể nhân bản mà không làm giảm chất lượng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e90f3347-383d-467b-9966-2e29e9490148','8a1ac06d-b116-4e1b-887f-2f2c0463f22d',363,'text','**Cách thực hiện**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('92c2462a-031e-4e4f-9cd4-4b300f30e957','8a1ac06d-b116-4e1b-887f-2f2c0463f22d',364,'text','- Mở rộng theo module, chi nhánh hoặc gói sản phẩm phù hợp.- Ưu tiên scale những phần đã có SOP, KPI và dashboard.- Kiểm soát tốc độ mở rộng bằng năng lực đội ngũ và dữ liệu.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0ff8b1f1-b789-4919-8b43-ea3f483f6109','8a1ac06d-b116-4e1b-887f-2f2c0463f22d',365,'text','**Đầu ra bắt buộc**',NULL,NULL,NULL,NULL,NULL);
