INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('dbae9617-c2e0-4481-ba6d-5e8195301a37','8a1ac06d-b116-4e1b-887f-2f2c0463f22d',369,'text','**KPI / tín hiệu theo dõi**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a88b7eb9-cf0d-46fe-9b09-1d87fafde49a','8a1ac06d-b116-4e1b-887f-2f2c0463f22d',370,'text','- Số điểm mở rộng thành công.- Doanh thu tăng mà chất lượng không giảm.- Tỷ lệ lỗi không tăng theo quy mô.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('67d78837-5002-49ab-be1c-5f1678cd1440','05-ung-dung-roadmap','17c8a3f3-51a2-480b-8cb4-b3b1634715ec',2,'P - Propagate','p-propagate',61,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e6a8e33a-a892-4617-ba1d-13d49b64094e','67d78837-5002-49ab-be1c-5f1678cd1440',371,'text','**Mục tiêu của bước này**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e4ca342b-4235-48a4-b75a-7fcce98b095f','67d78837-5002-49ab-be1c-5f1678cd1440',372,'text','Propagate là lan truyền giá trị qua referral, cộng đồng và các lớp tài sản niềm tin. Đây là lúc giá trị đi xa hơn khỏi phòng khám và tự tạo thêm đà tăng trưởng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('8c7ec493-ac96-4019-95a3-14d512a80a96','67d78837-5002-49ab-be1c-5f1678cd1440',373,'text','**Dấu hiệu cần thực hiện**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('90ceaee7-70b0-48d7-ac5f-563c54b759f1','67d78837-5002-49ab-be1c-5f1678cd1440',374,'text','Cần Propagate khi hệ thống đã có giá trị thật nhưng chưa được lan truyền rộng qua người dùng hiện tại.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f261785c-0d14-4fe6-9bec-b3ff90bc8884','67d78837-5002-49ab-be1c-5f1678cd1440',375,'text','**Cách thực hiện**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b0239e23-ad7e-4882-a112-ef2b45778347','67d78837-5002-49ab-be1c-5f1678cd1440',376,'text','- Thiết kế referral flow và testimonial flow.- Kích hoạt cộng đồng bệnh nhân.- Dùng case thật và review để lan truyền uy tín.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('8186c35a-debf-4363-bc48-c479358d5c3a','67d78837-5002-49ab-be1c-5f1678cd1440',377,'text','**Đầu ra bắt buộc**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ef03cc78-cd82-4cd2-ba08-ea841d37df3a','67d78837-5002-49ab-be1c-5f1678cd1440',378,'text','- Referral program.- Community plan.- Testimonial system.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('efc0b91d-1505-4509-b0d1-e3c58e25533a','67d78837-5002-49ab-be1c-5f1678cd1440',379,'text','**Người phụ trách**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('fb9edb75-12f1-4e75-8b04-87f81cbd41d9','67d78837-5002-49ab-be1c-5f1678cd1440',380,'text','Referral Lead, CSKH Lead, Marketing Lead.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ebcc4184-ea2b-47d4-ac41-ca618912b6a4','67d78837-5002-49ab-be1c-5f1678cd1440',381,'text','**KPI / tín hiệu theo dõi**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b445a285-bfeb-4da2-85fd-92352319b190','67d78837-5002-49ab-be1c-5f1678cd1440',382,'text','- Referral share of new patients.- Tỷ lệ review tăng.- Tỷ lệ khách cũ giới thiệu khách mới.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('c62d5d33-e7b5-4982-b9b1-01173a27902a','05-ung-dung-roadmap','17c8a3f3-51a2-480b-8cb4-b3b1634715ec',2,'E - Enrich','e-enrich',62,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('721cc4d2-75b2-4ee3-947a-6fea7022cf91','c62d5d33-e7b5-4982-b9b1-01173a27902a',383,'text','**Mục tiêu của bước này**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f0872745-fac2-4923-b182-da80bac79ea8','c62d5d33-e7b5-4982-b9b1-01173a27902a',384,'text','Enrich là làm giàu hệ sinh thái bằng dữ liệu, kinh nghiệm và nguồn lực mới. Khi hệ thống giàu hơn, nó không chỉ có thêm tài sản mà còn có thêm chiều sâu để tiếp tục phát triển.',NULL,NULL,NULL,NULL,NULL);
